from collections import deque

def solve(grid):
    import copy
    grid = [list(row) for row in grid]
    H = len(grid)
    W = len(grid[0])

    # Find center (value 2)
    cr, cc = None, None
    for r in range(H):
        for c in range(W):
            if grid[r][c] == 2:
                cr, cc = r, c
                break
        if cr is not None:
            break

    # BFS from 3x3 border cells (value 3) through non-6, non-3, non-2 cells
    start_cells = []
    for dr in range(-1, 2):
        for dc in range(-1, 2):
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W and grid[r][c] == 3:
                start_cells.append((r, c))

    bfs_dist = {}
    queue = deque()
    for r, c in start_cells:
        bfs_dist[(r, c)] = 0
        queue.append((r, c))

    while queue:
        r, c = queue.popleft()
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W and (nr, nc) not in bfs_dist:
                if grid[nr][nc] not in (6, 2, 3):
                    bfs_dist[(nr, nc)] = bfs_dist[(r, c)] + 1
                    queue.append((nr, nc))

    # Find reachable 9s sorted by distance
    reachable_9s = []
    for r in range(H):
        for c in range(W):
            if grid[r][c] == 9 and (r, c) in bfs_dist:
                reachable_9s.append((bfs_dist[(r, c)], r, c))
    reachable_9s.sort()

    N = min(len(reachable_9s), 9)

    result = copy.deepcopy(grid)

    # Remove N closest 9s
    for k in range(N):
        _, r, c = reachable_9s[k]
        result[r][c] = 7

    # Fill first N cells of 3x3 in reading order with 9
    fill_order = []
    for dr in range(-1, 2):
        for dc in range(-1, 2):
            fill_order.append((cr + dr, cc + dc))

    for k in range(N):
        r, c = fill_order[k]
        result[r][c] = 9

    return result

